import { describe, expect, it } from 'vitest';
import { assertGoldenPngEquals } from './helpers/golden-png-snapshot';
import { rgbFloat01InterleavedToPngBuffer } from './helpers/rgb-float01-to-png';
import { forkRaceFoldStyleTransfer } from '../src/forkRaceFoldStyleTransfer';

function makePlane(w: number, h: number, seed: number): Float32Array {
  const out = new Float32Array(w * h * 3);
  let s = seed >>> 0;
  const rand = () => {
    s = (s * 1664525 + 1013904223) >>> 0;
    return s / 0xffffffff;
  };
  for (let i = 0; i < out.length; i++) out[i] = rand();
  return out;
}

describe('style transfer FRF golden PNG', () => {
  it('forkRaceFoldStyleTransfer mesh fold 16×16 matches golden bytes', async () => {
    const w = 16;
    const h = 16;
    const content = makePlane(w, h, 7);
    const style = makePlane(w, h, 8);
    const frf = await forkRaceFoldStyleTransfer({
      content: { data: content, width: w, height: h, channels: 3 },
      style: { data: style, width: w, height: h, channels: 3 },
      meshFoldRankWeights: { topology: 0.35, depth: 0.1 },
      configs: [
        {
          label: 'lo',
          options: {
            method: 'classical',
            strength: 0.55,
            structurePreservation: 0.4,
            alphaWave: false,
            meshGate: { enabled: true },
          },
        },
        {
          label: 'hi',
          options: {
            method: 'classical',
            strength: 0.92,
            structurePreservation: 0.4,
            alphaWave: false,
            meshGate: { enabled: true },
          },
        },
      ],
    });
    const png = rgbFloat01InterleavedToPngBuffer(frf.stylized, w, h);
    assertGoldenPngEquals(png, 'frf-mesh-fold-16');
    expect(frf.candidates.length).toBe(2);
    expect(frf.candidates[0]?.compositeFoldScore).toBeDefined();
  });
});
